function Stars(){
  const r=useRef();
  useEffect(()=>{
    const c=r.current,ctx=c.getContext("2d");
    let W=c.width=window.innerWidth,H=c.height=window.innerHeight;
    const s=Array.from({length:180},()=>({x:Math.random()*W,y:Math.random()*H,r:Math.random()*1.3+.2,a:Math.random(),d:Math.random()*.004+.001}));
    let raf;const draw=()=>{ctx.clearRect(0,0,W,H);s.forEach(p=>{p.a+=p.d;if(p.a>1||p.a<0)p.d=-p.d;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=`rgba(212,175,55,${Math.abs(p.a)})`;ctx.fill();});raf=requestAnimationFrame(draw);};draw();
    const rz=()=>{W=c.width=window.innerWidth;H=c.height=window.innerHeight;};window.addEventListener("resize",rz);
    return()=>{cancelAnimationFrame(raf);window.removeEventListener("resize",rz);};
  },[]);
  return <canvas ref={r} style={{position:"fixed",top:0,left:0,pointerEvents:"none",zIndex:0}}/>;
}

function useCD(){
  const tgt=new Date("2036-01-01T00:00:00Z").getTime();
  const calc=()=>{const d=tgt-Date.now();if(d<=0)return{d:0,h:0,m:0,s:0};return{d:Math.floor(d/86400000),h:Math.floor((d%86400000)/3600000),m:Math.floor((d%3600000)/60000),s:Math.floor((d%60000)/1000)};};
  const[t,setT]=useState(calc);
  useEffect(()=>{const id=setInterval(()=>setT(calc()),1000);return()=>clearInterval(id);},[]);
  return t;
}

function useAnim(tgt){
  const[v,setV]=useState(0);
  useEffect(()=>{let i=0,steps=60;const id=setInterval(()=>{i++;setV(Math.floor(tgt*(i/steps)));if(i>=steps){setV(tgt);clearInterval(id);}},20);return()=>clearInterval(id);},[tgt]);
  return v;
}

